import {
  onPostChangecreateActin,
  addPostcreateActin,
} from "../../redux/messegData-reducer";
import { useSelector } from "react-redux";
import { useDispatch } from "react-redux";

export const ContactsState = () => {
  let a = useSelector((state) => state.messeges);
  return a;
};

export const ContactsDispatchOnCh = (text) =>
  useDispatch((dispatch) => dispatch(onPostChangecreateActin(text)));

export const ContactsDispatchAdd = () =>
  useDispatch((dispatch) => dispatch(addPostcreateActin()));
